#!/usr/bin/env node
import { readFileSync } from "node:fs";

const FORBIDDEN = [
  "docs/examples/vibe-self-plan.json",
  "packages/language/src/generated/",
  "packages/vscode-extension/syntaxes/vibe.tmLanguage.json",
];

const REASONS = {
  "docs/examples/vibe-self-plan.json":
    "This file is generated from examples/vibe-self.vibe. Edit the .vibe source, then run `pnpm run self:plan`.",
  "packages/language/src/generated/":
    "This directory is regenerated by `pnpm --filter @vibe/language langium:generate`. Edit the .langium grammar instead.",
  "packages/vscode-extension/syntaxes/vibe.tmLanguage.json":
    "This grammar is generated. Edit the upstream syntax source, then rebuild.",
};

let payload;
try {
  payload = JSON.parse(readFileSync(0, "utf8"));
} catch {
  process.exit(0);
}

const filePath = payload?.tool_input?.file_path;
if (typeof filePath !== "string") process.exit(0);

const normalized = filePath.replaceAll("\\", "/");
const hit = FORBIDDEN.find((p) => normalized.endsWith(p) || normalized.includes(p));
if (!hit) process.exit(0);

process.stderr.write(`Blocked edit to generated artifact: ${filePath}\n${REASONS[hit]}\n`);
process.exit(2);
